import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Star } from '@mui/icons-material';
import response from './response.json';

interface Movie {
  title: string;
  rating: number;
  genre: string;
  runtime: number;
}

interface MoviesData {
  topPicks: Movie[];
}

export default function Widget() {
  const moviesData = response.data as MoviesData;
  const { topPicks } = moviesData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#FF5722', fontWeight: 600 }}>
            Top Movie Picks
          </Typography>
          {topPicks.map((movie, index) => (
            <Box key={index} sx={{ bgcolor: '#1F1F1F', borderRadius: 1, p: 1.5 }}>
              <Typography variant="body1" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                {movie.title}
              </Typography>
              <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
                <Star sx={{ fontSize: 16, color: '#FFC107' }} />
                <Typography variant="body2" sx={{ color: '#FFC107' }}>
                  {movie.rating}
                </Typography>
              </Stack>
              <Stack direction="row" spacing={0.5} sx={{ mt: 1 }}>
                <Chip label={movie.genre} sx={{ fontSize: '10px', bgcolor: '#FF5722', color: '#FFFFFF', px: 1 }} />
                <Chip label={`${movie.runtime} min`} sx={{ fontSize: '10px', bgcolor: '#FF5722', color: '#FFFFFF', px: 1 }} />
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
